dashboard.definition:
{
  "title": "Source - Retail Orders",
  "description": "E-commerce order data — revenue tracking, product analytics, and customer activity",
  "dataSources": {
    "ds_total_orders": {
      "type": "ds.search",
      "name": "Total Orders Over Time",
      "options": {
        "query": "| tstats count where index=fake_tshrt sourcetype=\"FAKE:online:order\" by _time span=1h"
      }
    },
    "ds_total_revenue": {
      "type": "ds.search",
      "name": "Total Revenue",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:online:order\" | spath path=pricing.total output=order_total | stats sum(order_total) as count | eval count=\"$\".tostring(round(count,2),\"commas\")"
      }
    },
    "ds_avg_order_value": {
      "type": "ds.search",
      "name": "Average Order Value",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:online:order\" | spath path=pricing.total output=order_total | stats avg(order_total) as count | eval count=\"$\".tostring(round(count,2),\"commas\")"
      }
    },
    "ds_unique_customers": {
      "type": "ds.search",
      "name": "Unique Customers",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:online:order\" customerId=* | stats dc(customerId) as count"
      }
    },
    "ds_orders_over_time": {
      "type": "ds.search",
      "name": "Orders Over Time",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:online:order\" | timechart span=1h count"
      }
    },
    "ds_revenue_by_type": {
      "type": "ds.search",
      "name": "Revenue by Product Type",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:online:order\" | spath path=items{}.category output=product_category | spath path=pricing.total output=order_total | stats sum(order_total) as revenue by product_category | sort -revenue"
      }
    },
    "ds_top_products": {
      "type": "ds.search",
      "name": "Top Products by Order Count",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:online:order\" | spath path=items{}.name output=product_name | stats count by product_name | sort -count | head 15 | rename product_name as \"Product\""
      }
    },
    "ds_top_customers": {
      "type": "ds.search",
      "name": "Top Customers by Order Count",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:online:order\" customerId=* | stats count by customerId | sort -count | head 15 | rename customerId as \"Customer\""
      }
    },
    "ds_order_status": {
      "type": "ds.search",
      "name": "Order Status Distribution",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:online:order\" status=* | stats count by status | sort -count"
      }
    },
    "ds_recent_orders": {
      "type": "ds.search",
      "name": "Recent Orders",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:online:order\" | spath path=pricing.total output=order_total | spath path=items{}.name output=product_name | table _time orderId customerId product_name order_total status | sort -_time | head 30 | rename orderId as \"Order ID\" customerId as \"Customer\" product_name as \"Product\" order_total as \"Total\" status as \"Status\""
      }
    }
  },
  "visualizations": {
    "viz_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "# Source — Retail Orders\n\n**Sourcetype:** `FAKE:online:order` | **Coverage:** E-commerce platform | **Format:** JSON\n\n**Why monitor?** Track revenue in real-time — detect order processing failures, identify top products, monitor customer activity.",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_kpi_total_orders": {
      "type": "splunk.singlevalue",
      "title": "Total Orders",
      "dataSources": { "primary": "ds_total_orders" },
      "options": {
        "majorValue": "> sparklineValues | lastPoint()",
        "sparklineValues": "> primary | seriesByName('count')",
        "sparklineDisplay": "below",
        "majorColor": "#00D2FF",
        "backgroundColor": "transparent",
        "showSparklineAreaGraph": true,
        "sparklineStrokeColor": "#00D2FF"
      }
    },
    "viz_kpi_revenue": {
      "type": "splunk.singlevalue",
      "title": "Revenue",
      "dataSources": { "primary": "ds_total_revenue" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#53A051",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_avg_order": {
      "type": "splunk.singlevalue",
      "title": "Avg Order Value",
      "dataSources": { "primary": "ds_avg_order_value" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#F8BE34",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_customers": {
      "type": "splunk.singlevalue",
      "title": "Unique Customers",
      "dataSources": { "primary": "ds_unique_customers" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#7B56DB",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_orders_over_time": {
      "type": "splunk.area",
      "title": "Orders Over Time",
      "dataSources": { "primary": "ds_orders_over_time" },
      "options": {
        "legendDisplay": "off",
        "nullValueDisplay": "zero",
        "areaOpacity": 0.7,
        "backgroundColor": "transparent",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "Orders / hour",
        "yAxisTitleVisibility": "show",
        "yAxisAbbreviation": "auto",
        "seriesColors": ["#00D2FF"]
      },
      "showProgressBar": true,
      "showLastUpdated": true
    },
    "viz_revenue_by_type": {
      "type": "splunk.pie",
      "title": "Revenue by Product Type",
      "dataSources": { "primary": "ds_revenue_by_type" },
      "options": {
        "labelDisplay": "valuesAndPercentage",
        "showDonutHole": true,
        "seriesColors": ["#00D2FF", "#7B56DB", "#53A051", "#F8BE34", "#DC4E41", "#009CEB", "#F1813F", "#00CDAF"]
      }
    },
    "viz_top_products": {
      "type": "splunk.bar",
      "title": "Top Products by Order Count",
      "dataSources": { "primary": "ds_top_products" },
      "options": {
        "seriesColors": ["#53A051"],
        "legendDisplay": "off",
        "xAxisTitleText": "Orders",
        "xAxisTitleVisibility": "show",
        "yAxisTitleVisibility": "hide",
        "backgroundColor": "transparent"
      },
      "showProgressBar": true
    },
    "viz_top_customers": {
      "type": "splunk.bar",
      "title": "Top Customers by Order Count",
      "dataSources": { "primary": "ds_top_customers" },
      "options": {
        "seriesColors": ["#7B56DB"],
        "legendDisplay": "off",
        "xAxisTitleText": "Orders",
        "xAxisTitleVisibility": "show",
        "yAxisTitleVisibility": "hide",
        "backgroundColor": "transparent"
      },
      "showProgressBar": true
    },
    "viz_order_status": {
      "type": "splunk.pie",
      "title": "Order Status Distribution",
      "dataSources": { "primary": "ds_order_status" },
      "options": {
        "labelDisplay": "valuesAndPercentage",
        "showDonutHole": true,
        "seriesColorsByField": {
          "delivered": "#53A051",
          "shipped": "#00D2FF",
          "processing": "#F8BE34",
          "pending": "#7B56DB",
          "cancelled": "#DC4E41",
          "returned": "#F1813F"
        }
      }
    },
    "viz_recent_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "### Recent Orders",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_recent_orders": {
      "type": "splunk.table",
      "title": "Recent Orders",
      "dataSources": { "primary": "ds_recent_orders" },
      "options": {
        "count": 20,
        "showRowNumbers": false
      },
      "showProgressBar": true,
      "showLastUpdated": true
    }
  },
  "inputs": {
    "input_global_trp": {
      "type": "input.timerange",
      "title": "Time Range",
      "options": {
        "token": "global_time",
        "defaultValue": "1767225600,1769904000"
      }
    }
  },
  "defaults": {
    "dataSources": {
      "ds.search": {
        "options": {
          "queryParameters": {
            "earliest": "$global_time.earliest$",
            "latest": "$global_time.latest$"
          }
        }
      }
    }
  },
  "layout": {
    "type": "grid",
    "globalInputs": ["input_global_trp"],
    "structure": [
      { "item": "viz_header", "type": "block", "position": { "x": 0, "y": 0, "w": 1200, "h": 130 } },
      { "item": "viz_kpi_total_orders", "type": "block", "position": { "x": 0, "y": 130, "w": 300, "h": 120 } },
      { "item": "viz_kpi_revenue", "type": "block", "position": { "x": 300, "y": 130, "w": 300, "h": 120 } },
      { "item": "viz_kpi_avg_order", "type": "block", "position": { "x": 600, "y": 130, "w": 300, "h": 120 } },
      { "item": "viz_kpi_customers", "type": "block", "position": { "x": 900, "y": 130, "w": 300, "h": 120 } },
      { "item": "viz_orders_over_time", "type": "block", "position": { "x": 0, "y": 250, "w": 750, "h": 350 } },
      { "item": "viz_revenue_by_type", "type": "block", "position": { "x": 750, "y": 250, "w": 450, "h": 350 } },
      { "item": "viz_top_products", "type": "block", "position": { "x": 0, "y": 600, "w": 600, "h": 300 } },
      { "item": "viz_top_customers", "type": "block", "position": { "x": 600, "y": 600, "w": 600, "h": 300 } },
      { "item": "viz_order_status", "type": "block", "position": { "x": 0, "y": 900, "w": 1200, "h": 300 } },
      { "item": "viz_recent_header", "type": "block", "position": { "x": 0, "y": 1200, "w": 1200, "h": 50 } },
      { "item": "viz_recent_orders", "type": "block", "position": { "x": 0, "y": 1250, "w": 1200, "h": 400 } }
    ]
  }
}
